import React, { useState, useRef , useEffect } from "react";
import { useDispatch , useSelector } from 'react-redux';

import { connect } from 'react-redux';
import '../LoginForm.css';
import DataTable from './DataTable';
import { fetchDataAndSet } from '../actions/dataActions';

const POLL_INTERVAL = 5000; // 5000 milliseconds or 5 seconds

const UserRegistrationTable = ({ cakeReducer }) => {

  const columns = [
    { Header: 'User Name', accessor: 'userName' ,  sortType: 'basic'},
    { Header: 'Password', accessor: 'password' },
    { Header: 'Inactive', accessor: 'inActive', Cell: ({ value }) => (value ? 'Yes' : 'No') },
    { Header: 'Gender', accessor: 'gender' },
    { Header: 'Country', accessor: 'country' },
    { Header: 'Email ID', accessor: 'emailId' },
    { Header: 'Phone Number', accessor: 'phoneNumber' },
    { Header: 'Create Date', accessor: 'createDate' , Cell: ({ value }) => <div>{value}</div>}
  ];

  const dispatch = useDispatch();
  const data = useSelector((state) => state.data);
  useEffect(() => {
    let timeoutId;
    const poll = () => {
      dispatch(fetchDataAndSet());
      timeoutId = setTimeout(poll, POLL_INTERVAL);
    };
    
    poll();
    console.log("polling");
    // Clean up timeout on component unmount
    return () => clearTimeout(timeoutId);
  }, [dispatch]);

   return (

   <>
    <DataTable columns={columns} data={data.data1} />
    </>
    );
    
};

//const Home = MotionHoc(HomeComponent);
//  cakeReducer: state.cakeReducer,
const mapStateToProps = (state) => ({
  cakeReducer: state.data,
});
//
// const mapDispatchToProps = (dispatch) => ({
//  increment: () => dispatch(increment()),
// });
// connect(mapStateToProps , mapDispatchToProps)
export default connect(mapStateToProps ) (UserRegistrationTable);
