
import axios from "axios";



// actions.js
import {
  FETCH_DATA_REQUEST,
  FETCH_DATA_SUCCESS,
  FETCH_DATA_FAILURE,
} from './actionTypes';

const API_URL = "http://localhost:8100/gradleproject";

const fetchDataRequest = () => ({
  type: FETCH_DATA_REQUEST,
});

const fetchDataSuccess = (data) => ({
  type: FETCH_DATA_SUCCESS,
  payload: data,
});

const fetchDataFailure = (error) => ({
  type: FETCH_DATA_FAILURE,
  payload: error,
});

export const fetchData = () => {
  return async (dispatch) => {
    dispatch(fetchDataRequest());
    try {
      // Simulate API response
      const res = await axios.get(`http://localhost:8100/gradleproject/userdetails`)
        const response = `
           [
             {
               "id": 1,
               "username": "firstName4",
               "email": "email4@mail.com",
               "password": "lastName4"
             }
           ]`;
     // const data = JSON.parse(res); // Parse JSON string to object
      console.log("response : " + res);
      dispatch(fetchDataSuccess(res));
      return res; // Resolve the promise with response data
    } catch (error) {
      dispatch(fetchDataFailure(error.message));
      throw error; // Reject the promise with the error
    }
  };
};



export const login = (userName, password ,  emailId ) => {
  return async (dispatch) => {
    dispatch(fetchDataRequest());
    var res = '';
    var isActive = false;
    try {
      // Simulate API response

      const jwtResponseDTO = {
      //  token: 'your-jwt-token',
        username: userName,
        password:password
      };

       // Perform the API call
       const response = await axios.post(API_URL + "/login", jwtResponseDTO, {
        headers: {
          'Content-Type': 'application/json'
        }
      });

      // Log the success response
      console.log('Success:', response.data);

      // Extract the relevant data from response
      const res = response.data;

      // Dispatch success action with the response data
      dispatch(fetchDataSuccess(res));

       // Return the response data
       return res;

    } catch (error) {

      // Handle any errors that occur
      console.error('Error:', error.response ? error.response.data : error.message);

      dispatch(fetchDataFailure(error.message));
      throw error; // Reject the promise with the error
    }
  };
};

