const initialState = {
  value: 0,
};

const INCREMENT = 'INCREMENT';

export const increment = () => ({
  type: INCREMENT,
});

export default function (state = initialState, action) {
  switch (action.type) {
    case 'INCREMENT':
      return { ...state, value: state.value + 1 };
    default:
      return state;
  }
}
