import {
    SET_DATA
  } from "../actions/actionTypes";


export const setData = (data) => ({
    type: SET_DATA,
    payload: data,
  });

  const dataReducer = (state = {}, action) => {
    switch (action.type) {
      case SET_DATA:
        return { ...state, ...action.payload };
      default:
        return state;
    }
  };
  
  export default dataReducer;
  