import React, { useState, useRef , useEffect } from "react";

import MotionHoc from "./MotionHoc";
import { connect } from 'react-redux';
import { useDispatch , useSelector } from 'react-redux';
import { increment } from '../reducers/slidereducer';
import '../LoginForm.css';
import { homevalidation } from "../actions/auth";
import { fetchData  , login} from '../actions/homeActions';
import Dropdown from '../Pages/Dropdown';  // Import the default export
import { useNavigate } from 'react-router-dom';
import '../LoginForm.css';
import PopupModel from '../Pages/PopupModel';
// import Popup from '../Pages/Popup';
import api from '../api/attachtokentoapi'; 
// Adjust the import path as needed D:\tcs\webapplication\react-sidebar-new\src\api\attachtokentoapi.js
// src\api\attachtokentoapi.js

import Modal from 'react-modal';
import AddressForm from '../Pages/AddressForm';

const Home = () => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [message, setMessage] = useState('');
  const { id , username1 , email , password1} = useSelector((state) => state.homereducers.data);
  const [selectedOption, setSelectedOption] = useState('');
 // const response = await api.get('/user-profile');
  const form = useRef();
  const dispatch = useDispatch();
  const navigate = useNavigate();

  const [addresses, setAddresses] = useState([]);
  const [modalIsOpen, setModalIsOpen] = useState(false);

  const addAddress = (address) => {
    setAddresses([...addresses, address]);
  };

  const openModal = () => {
    setModalIsOpen(true);
  };

  const closeModal = () => {
    setModalIsOpen(false);
  };

 useEffect(() => {
     dispatch(fetchData(username, password))
       .then((data) => {

         setMessage('Fetch data successful!');
         console.log('Fetched data:', data);
         // Additional actions like navigation can go here
       })
       .catch((error) => {
         setMessage(`Fetch data failed: ${error.message}`);
         console.error('Error fetching data:', error);

       });
   }, [dispatch]);


  const handleUsernameChange = (e) => {
    setUsername(e.target.value);
  };

  const handlePasswordChange = (e) => {
    setPassword(e.target.value);
  };

  const handleDropdownChange = (value) => {
    setSelectedOption(value);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log('Username:', username);
    console.log('Password:', password);
    console.log('selectedOption:', selectedOption);
    console.log('Address:', addresses);


  };

   return (
   <>
    <div>
      <h6>Address Application</h6>
      <button onClick={openModal}>Add New Address</button>
      <Modal
        isOpen={modalIsOpen}
        onRequestClose={closeModal}
        contentLabel="Add Address"
      >
        <h2>Add New Address</h2>
        <AddressForm addAddress={addAddress} closeModal={closeModal} />
        <button onClick={closeModal}>Close</button>
      </Modal>
    </div>

      <div className="login-form-container">
        <h2>Login</h2>
        <form onSubmit={handleSubmit} ref={form}>
        <div className="form-group">
          <label htmlFor="username">Username:</label>
          <input
            type="text"
            id="username"
            value={username}
            onChange={handleUsernameChange}
            required
          />
        </div>

        <div className="form-group">
          <label htmlFor="password">Password:</label>
          <input
            type="password"
            id="password"
            value={password}
            onChange={handlePasswordChange}
            required
          />
        </div>

        <div className="form-group horizontal-container">
          <label htmlFor="password">Password:</label>
          <div>
             <button onClick={openModal}>Add New Address</button>
             <Modal
                 isOpen={modalIsOpen}
                 onRequestClose={closeModal}
                 contentLabel="Add Address"
              >
             <h2>Add New Address</h2>
             <AddressForm addAddress={addAddress} closeModal={closeModal} />
             <button onClick={closeModal}>Close</button>
             </Modal>
          </div>
        </div>
        
        <Dropdown selectedOption={selectedOption} handleDropdownChange={handleDropdownChange} />
        <button type="submit" className="login-button">Login</button>
      </form>
      {message && <p>{message}</p> }
      </div>
      </>
      
    );
};
export default (Home);
