// src/components/DataTable.js
import React , { useState , useMemo, useEffect } from 'react';
import { useTable , useSortBy} from 'react-table';
import '../LoginForm.css';

const DataTable = ({ columns, data }) => {

  console.log('Data Type:', typeof data);
  console.log('Data Content:', data);

  const [sortBy, setSortBy] = useState([]);
  const [sortInput, setSortInput] = useState('');
  const [filterInput, setFilterInput] = useState('');

  const handleFilterChange = (e) => {
      setFilterInput(e.target.value);
  };
  
    const handleSortInputChange = (e) => {
      const value = e.target.value.trim();
      setSortInput(value);
      if (value) {
        setSortBy([{ id: value, desc: false }]);
      } else {
        setSortBy([]);
      }
    };
  
    const filteredData = useMemo(() => {
      if (!filterInput) return data;
      return data.filter(row =>
        Object.values(row).some(
          val => val.toString().toLowerCase().includes(filterInput.toLowerCase())
        )
      );
    }, [data, filterInput]);
  
    const tableInstance = useTable(
      {
        columns,
        data: filteredData,
        initialState: { sortBy },
        manualSortBy: false,
      },
      useSortBy
    );
  
    const {
      getTableProps,
      getTableBodyProps,
      headerGroups,
      rows,
      prepareRow,
      setSortBy: updateSortBy,
    } = tableInstance;
  
    useEffect(() => {
      if (sortInput) {
        const column = columns.find(col => col.accessor === sortInput);
        if (column) {
          updateSortBy([{ id: sortInput, desc: false }]);
        }
      } else {
        updateSortBy([]);
      }
    }, [sortInput, columns, updateSortBy]);


  return (

    <>

      {/* <input
        type="text"
        placeholder="Enter column accessor to sort"
        value={sortInput}
        onChange={handleInputChange}
        style={{ marginBottom: '10px' }}
      /> */}

<div className="relative">
    <input
        type="text"
        placeholder="Filter records"
        value={filterInput}
        onChange={handleFilterChange}
        style={{ marginBottom: '10px', marginRight: '10px' }}
      />
      <input
        type="text"
        placeholder="Enter column accessor to sort"
        value={sortInput}
        onChange={handleSortInputChange}
        style={{ marginBottom: '10px' }}
      />
</div>


    <table {...getTableProps()}  className="datatable">
      <thead>
        {headerGroups.map(headerGroup => (
          <tr {...headerGroup.getHeaderGroupProps()}>
            {headerGroup.headers.map(column => (
              <th {...column.getHeaderProps(column.getSortByToggleProps())}>
                
                {column.render('Header')}
                {/* Add a sort indicator */}
                <span>
                  {column.isSorted
                    ? column.isSortedDesc
                      ? ' 🔽'
                      : ' 🔼'
                    : ''}
                </span>
                
              </th>
            ))}
          </tr>
        ))}
      </thead>
      <tbody {...getTableBodyProps()}>
        {rows.map(row => {
          prepareRow(row);
          return (
            <tr {...row.getRowProps()}>
              {row.cells.map(cell => (
                <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
              ))}
            </tr>
          );
        })}
      </tbody>
    </table>
  
    </>
  );
};

export default DataTable;
