import { SET_DATA } from '../actions/actionTypes';

export const setData = (data) => ({
  type: SET_DATA,
  payload: data,
});

// Async action creator
export const fetchDataAndSet = () => {
    return async (dispatch) => {
      try {
        const response1 = await fetch('http://localhost:8100/gradleproject/userRegisterList');
        const data1 = await response1.json();
  
        const response2 = await fetch('http://localhost:8100/gradleproject/userRegisterList');
        const data2 = await response2.json();
  
        dispatch(setData({ data1, data2 }));
      } catch (error) {
        console.error('Error fetching data:', error);
      }
    };
  };